const express = require('express');
const session = require('express-session');
const jwtDecode = require('jwt-decode');
const fetch = require('node-fetch').default;

const app = express();
app.use(session({ secret: 'your_secret_key', resave: false, saveUninitialized: true }));

// Replace with your own details
const CLIENT_ID = 'your_client_id';
const CLIENT_SECRET = 'your_client_secret';
const REDIRECT_URI = 'http://localhost:3000/callback';
const AUTHORIZATION_ENDPOINT = 'https://accounts.google.com/o/oauth2/v2/auth';
const TOKEN_ENDPOINT = 'https://www.googleapis.<｜begin▁of▁sentence｜>com/oauth2/v4/token'; // replace with your token endpoint

app.get('/login', (req, res) => {
  const params = new URLSearchParams({
    client_id: CLIENT_ID,
    redirect_uri: REDIRECT_URI,
    response_type: 'code',
    scope: 'openid email profile'
  });
  
  res.redirect(`${AUTHORIZATION_ENDPOINT}?${params.toString()}`);
});

app.get('/callback', async (req, res) => {
  const code = req.query.code;

  if (!code) return res.send('Error: no code received');
  
  const params = new URLSearchParams({
    client_id: CLIENT_ID,
    client_secret: CLIENT_SECRET,
    redirect_uri: REDIRECT_URI,
    grant_type: 'authorization_code',
    code
  });
  
  const response = await fetch(`${TOKEN_ENDPOINT}?${params.toString()}`, { method: 'POST' });
  const tokens = await response.json();

  if (response.status !== 200) return res.send('Error: invalid token response');
  
  req.session.tokens = tokens;
  res.redirect('/profile');
});

app.get('/profile', (req, res) => {
  const { id_token } = req.session.tokens;
  if (!id_token) return res.send('Error: no token present');
  
  const decodedToken = jwtDecode(id_token);
  req.session.profile = decodedToken;
  
  res.json({ profile: req.session.profile });
});

app.listen(3000, () => console.log('Server started on port 3000'));